mapper.select:
select * from `health_item`

    and health_item.name like concat('%', #{name}, '%')
    and health_item.user_id = #{userId}
    and health_item.is_global = #{isGlobal}

        and health_item.create_time between #{startTime} and #{endTime}


order by id desc

mapper.update:
update `health_item` set name = #{name}, detail = #{detail}, icon_url = #{iconUrl}, unit = #{unit},
symbol = #{symbol}, normal_value = #{normalValue}
where id = #{id}

mapper.select:
select hi.id as value, hi.name as label, hi.unit as unit, hi.detail from `health_item` hi

    and hi.user_id = #{userId}
    and hi.is_global = #{isGlobal}

order by id desc
